BEGIN
  IF AD_isTriggerEnabled()='N' THEN RETURN;
  END IF;
	-- Verificar registros duplciados

  -- Validación en INSERT
  IF INSERTING THEN
    IF EXISTS (
      SELECT 1
      FROM scft_paramacct
      WHERE name = :NEW.name
    ) THEN
      RAISE_APPLICATION_ERROR(-20000, '@scft_duplicatetrg@');
    END IF;
  END IF;

  -- Validación en UPDATE solo si cambió el name
  IF UPDATING THEN
    IF :NEW.name IS DISTINCT FROM :OLD.name THEN
      IF EXISTS (
        SELECT 1
        FROM scft_paramacct
        WHERE name = :NEW.name
          AND scft_paramacct_id <> :OLD.scft_paramacct_id
      ) THEN
        RAISE_APPLICATION_ERROR(-20000, '@scft_duplicatetrg@');
      END IF;
    END IF;
  END IF;
END SCFT_PARAMACCT_CKNAME_TRG
